  // Privacy Section
  "landing.privacy.title": { en: "Family Data Sovereignty", hi: "पारिवारिक डेटा संप्रभुता", mr: "कौटुंबिक डेटा सार्वभौमत्व", gu: "કૌટુંબિક ડેટા સાર્વભૌમત્વ", pa: "ਪਾਰਿਵਾਰਿਕ ਡਾਟਾ ਪ੍ਰਭੂਸੱਤਾ", ta: "குடும்ப தரவு இறையாண்மை", bho: "पारिवारिक डेटा के संप्रभुता", kn: "ಕುಟುಂಬ ಡೇಟಾ ಸಾರ್ವಭೌಮತ್ವ", te: "కుటుంబ డేటా సార్వభౌమాధికారం", ne: "पारिवारिक डेटा सार्वभौमिकता", bn: "পারিবারিক ডেটা সার্বভৌমত্ব", mni: "ইমুংগী দেতা সোভরেন্তী" },
  "landing.privacy.desc": { 
    en: "Your data is encrypted before it's even written to disk. We don't have the keys. We don't have the data. You have the air-gap.", 
    hi: "आपका डेटा डिस्क पर लिखे जाने से पहले ही एन्क्रिप्ट हो जाता है। हमारे पास चाबियाँ नहीं हैं। हमारे पास डेटा नहीं है। आपके पास एयर-गैप है।", 
    mr: "तुमचा डेटा डिस्कवर लिहिण्यापूर्वीच एनक्रिप्ट केला जातो. आमच्याकडे चाव्या नाहीत, डेटाही नाही.",
    gu: "તમારો ડેટા ડિસ્ક પર લખતા પહેલા જ એન્ક્રિપ્ટ થઈ જાય છે. અમારી પાસે ચાવીઓ નથી કે ડેટા નથી.",
    pa: "ਤੁਹਾਡਾ ਡਾਟਾ ਡਿਸਕ 'ਤੇ ਲਿਖਣ ਤੋਂ ਪਹਿਲਾਂ ਹੀ ਐਨਕ੍ਰਿਪਟ ਹੋ ਜਾਂਦਾ ਹੈ। ਸਾਡੇ ਕੋਲ ਚਾਬੀਆਂ ਨਹੀਂ ਹਨ।",
    ta: "உங்கள் தரவு வட்டில் எழுதப்படுவதற்கு முன்பே குறியாக்கம் செய்யப்படுகிறது. எங்களிடம் சாவிகள் இல்லை. தரவு இல்லை.",
    bho: "डेटा लिखे से पहिले ही सुरक्षित कइल जाला। हमनी के लगे चाबी नईखे ना डेटा बा।",
    kn: "ನಿಮ್ಮ ಡೇಟಾವನ್ನು ಡಿಸ್ಕ್‌ಗೆ ಬರೆಯುವ ಮೊದಲೇ ಎನ್‌ಕ್ರಿಪ್ಟ್ ಮಾಡಲಾಗುತ್ತದೆ. ಕೀಗಳು ಅಥವಾ ಡೇಟಾ ನಮ್ಮ ಬಳಿ ಇಲ್ಲ.",
    te: "మీ డేటా డిస్క్‌పై వ్రాయబడే ముందే ఎన్క్రిప్ట్ చేయబడుతుంది. మా దగ్గర కీలు లేవు, డేటా లేదు.",
    ne: "तपाईँको डेटा डिस्कमा लेखिनु अघि नै इन्क्रिप्ट गरिन्छ। हामीसँग कुञ्जीहरू छैनन्, न त डेटा नै छ।",
    bn: "আপনার ডেটা ডিস্কে লেখার আগেই এনক্রিপ্ট হয়ে যায়। আমাদের কাছে কোনো কী নেই, কোনো ডেটাও নেই। আপনার কাছে এয়ার-গ্যাপ আছে।",
    mni: "নহাক্কী দেতা অদু দিস্কতা ইদ্রিঙইদগী এনক্রিপ্ট তৌই। ঐখোয়গী মফমদা চাবি লৈতে।"
  },
  "landing.privacy.quote": { en: "Privacy is not a feature, it is the foundation.", hi: "गोपनीयता कोई सुविधा नहीं है, यह आधार है।", mr: "गोपनीयता हे वैशिष्ट्य नाही, तो पाया आहे.", gu: "ગોપનીયતા એ વિશેષતા નથી, તે પાયો છે.", pa: "ਪਰਦੇਦਾਰੀ ਕੋਈ ਵਿਸ਼ੇਸ਼ਤਾ ਨਹੀਂ ਹੈ, ਇਹ ਬੁਨਿਆਦ ਹੈ।", ta: "தனியுரிமை ஒரு அம்சம் அல்ல, அதுவே அடிப்படை.", bho: "गोपनीयता कौनों सुविधा ना हवे, ई आधार हऽ।", kn: "ಗೌಪ್ಯತೆಯು ಕೇವಲ ಒಂದು ವೈಶಿಷ್ಟ್ಯವಲ್ಲ, ಅದು ಅಡಿಪಾಯ.", te: "గోప్యత అనేది ఒక ఫీచర్ కాదు, అది పునాది.", ne: "गोपनीयता कुनै सुविधा होइन, यो आधार हो।", bn: "গোপনীয়তা কোনো বৈশিষ্ট্য নয়, এটিই ভিত্তি।", mni: "প্রাইভেসি অসি ফিচর অমা নত্তে, মসি উরেপ-চুপ্পনি।" },
